"""
pytest test suite for Patient Resource Creation
Requirement: A registered clinician shall create a patient resource with validated
demographics; creation with missing mandatory elements shall be rejected.
Boundary cases on timestamps and numeric elements must be tested.
"""

import pytest
import uuid
from datetime import datetime, date, timezone, timedelta
from unittest.mock import MagicMock, patch
from dataclasses import dataclass, field
from typing import Optional, List
from enum import Enum


# ---------------------------------------------------------------------------
# Domain model stubs (replace with real imports from your project)
# ---------------------------------------------------------------------------

class Gender(str, Enum):
    MALE = "male"
    FEMALE = "female"
    OTHER = "other"
    UNKNOWN = "unknown"


class ValidationError(Exception):
    """Raised when a patient resource fails validation."""
    def __init__(self, message: str, field: Optional[str] = None):
        super().__init__(message)
        self.field = field


class AuthorizationError(Exception):
    """Raised when the caller is not authorized."""


@dataclass
class HumanName:
    family: str
    given: List[str] = field(default_factory=list)
    prefix: Optional[str] = None


@dataclass
class ContactPoint:
    system: str          # phone | email
    value: str
    use: Optional[str] = None


@dataclass
class Address:
    line: List[str] = field(default_factory=list)
    city: Optional[str] = None
    postal_code: Optional[str] = None
    country: Optional[str] = None


@dataclass
class PatientResource:
    """Simplified FHIR-like Patient resource."""
    resource_type: str = "Patient"
    id: Optional[str] = None
    name: Optional[List[HumanName]] = None
    gender: Optional[Gender] = None
    birth_date: Optional[date] = None
    deceased_date_time: Optional[datetime] = None
    address: Optional[List[Address]] = None
    telecom: Optional[List[ContactPoint]] = None
    active: bool = True
    # Numeric / coded fields
    multiple_birth_integer: Optional[int] = None   # birth order
    weight_kg: Optional[float] = None
    height_cm: Optional[float] = None
    # Audit timestamps
    created_at: Optional[datetime] = None
    updated_at: Optional[datetime] = None
    # Clinician who registered the patient
    clinician_id: Optional[str] = None


# ---------------------------------------------------------------------------
# Service stub (replace with real import)
# ---------------------------------------------------------------------------

class PatientService:
    """
    Thin service layer that validates and persists a PatientResource.
    All validation rules live here so they can be tested in isolation.
    """

    MANDATORY_FIELDS = ("name", "gender", "birth_date", "clinician_id")
    MAX_WEIGHT_KG = 700.0
    MIN_WEIGHT_KG = 0.1
    MAX_HEIGHT_CM = 300.0
    MIN_HEIGHT_CM = 20.0
    MAX_MULTIPLE_BIRTH = 10
    MIN_MULTIPLE_BIRTH = 1
    MIN_BIRTH_YEAR = 1900

    def __init__(self, clinician_registry, patient_repository):
        self._clinician_registry = clinician_registry
        self._repo = patient_repository

    # ------------------------------------------------------------------
    def create_patient(self, resource: PatientResource) -> PatientResource:
        self._authorize(resource.clinician_id)
        self._validate_mandatory_fields(resource)
        self._validate_name(resource.name)
        self._validate_birth_date(resource.birth_date)
        self._validate_deceased_date_time(resource)
        self._validate_numeric_fields(resource)
        self._validate_telecom(resource.telecom)

        resource.id = str(uuid.uuid4())
        resource.created_at = datetime.now(timezone.utc)
        resource.updated_at = resource.created_at
        self._repo.save(resource)
        return resource

    # ------------------------------------------------------------------
    def _authorize(self, clinician_id: Optional[str]):
        if not clinician_id:
            raise AuthorizationError("clinician_id is required for authorization.")
        if not self._clinician_registry.is_registered(clinician_id):
            raise AuthorizationError(f"Clinician '{clinician_id}' is not registered.")

    # ------------------------------------------------------------------
    def _validate_mandatory_fields(self, resource: PatientResource):
        for f in self.MANDATORY_FIELDS:
            value = getattr(resource, f, None)
            if value is None or value == [] or value == "":
                raise ValidationError(
                    f"Mandatory field '{f}' is missing or empty.", field=f
                )

    # ------------------------------------------------------------------
    def _validate_name(self, names: List[HumanName]):
        for n in names:
            if not n.family or not n.family.strip():
                raise ValidationError(
                    "Name must include a non-empty family name.", field="name.family"
                )

    # ------------------------------------------------------------------
    def _validate_birth_date(self, birth_date: date):
        today = date.today()
        if birth_date > today:
            raise ValidationError(
                "birth_date cannot be in the future.", field="birth_date"
            )
        if birth_date.year < self.MIN_BIRTH_YEAR:
            raise ValidationError(
                f"birth_date year must be >= {self.MIN_BIRTH_YEAR}.", field="birth_date"
            )

    # ------------------------------------------------------------------
    def _validate_deceased_date_time(self, resource: PatientResource):
        if resource.deceased_date_time is None:
            return
        ddt = resource.deceased_date_time
        if ddt.tzinfo is None:
            raise ValidationError(
                "deceased_date_time must be timezone-aware.", field="deceased_date_time"
            )
        if resource.birth_date and ddt.date() < resource.birth_date:
            raise ValidationError(
                "deceased_date_time cannot precede birth_date.", field="deceased_date_time"
            )
        if ddt > datetime.now(timezone.utc):
            raise ValidationError(
                "deceased_date_time cannot be in the future.", field="deceased_date_time"
            )

    # ------------------------------------------------------------------
    def _validate_numeric_fields(self, resource: PatientResource):
        if resource.weight_kg is not None:
            if not (self.MIN_WEIGHT_KG <= resource.weight_kg <= self.MAX_WEIGHT_KG):
                raise ValidationError(
                    f"weight_kg must be between {self.MIN_WEIGHT_KG} and "
                    f"{self.MAX_WEIGHT_KG}.",
                    field="weight_kg",
                )
        if resource.height_cm is not None:
            if not (self.MIN_HEIGHT_CM <= resource.height_cm <= self.MAX_HEIGHT_CM):
                raise ValidationError(
                    f"height_cm must be between {self.MIN_HEIGHT_CM} and "
                    f"{self.MAX_HEIGHT_CM}.",
                    field="height_cm",
                )
        if resource.multiple_birth_integer is not None:
            if not (
                self.MIN_MULTIPLE_BIRTH
                <= resource.multiple_birth_integer
                <= self.MAX_MULTIPLE_BIRTH
            ):
                raise ValidationError(
                    f"multiple_birth_integer must be between "
                    f"{self.MIN_MULTIPLE_BIRTH} and {self.MAX_MULTIPLE_BIRTH}.",
                    field="multiple_birth_integer",
                )

    # ------------------------------------------------------------------
    def _validate_telecom(self, telecom: Optional[List[ContactPoint]]):
        if not telecom:
            return
        allowed_systems = {"phone", "email"}
        for cp in telecom:
            if cp.system not in allowed_systems:
                raise ValidationError(
                    f"Telecom system '{cp.system}' is not supported.",
                    field="telecom.system",
                )
            if not cp.value or not cp.value.strip():
                raise ValidationError(
                    "Telecom value must not be empty.", field="telecom.value"
                )


