def _assert_validation_error(exc_info, field_hint: Optional[str] = None):
    """Assert that a ValidationError was raised (and optionally check field)."""
    assert exc_info.type is ValidationError, (
        f"Expected ValidationError but got {exc_info.type}"
    )
    if field_hint:
        err = exc_info.value
        assert field_hint in (err.field or ""), (
            f"Expected field hint '{field_hint}' in '{err.field}'"
        )


