class TestDeceasedDateTime:
    def _past_aware(self, days=1):
        return datetime.now(timezone.utc) - timedelta(days=days)

    def test_valid_deceased_date_time_accepted(self, service, valid_resource):
        valid_resource.deceased_date_time = self._past_aware(days=100)
        result = service.create_patient(valid_resource)
        assert result.id is not None

    def test_naive_deceased_date_time_is_rejected(self, service, valid_resource):
        valid_resource.deceased_date_time = datetime(2020, 1, 1)  # naive
        with pytest.raises(ValidationError) as exc:
            service.create_patient(valid_resource)
        _assert_validation_error(exc, field_hint="deceased_date_time")

    def test_future_deceased_date_time_is_rejected(self, service, valid_resource):
        valid_resource.deceased_date_time = datetime.now(timezone.utc) + timedelta(
            days=1
        )
        with pytest.raises(ValidationError) as exc:
            service.create_patient(valid_resource)
        _assert_validation_error(exc, field_hint="deceased_date_time")

    def test_deceased_before_birth_is_rejected(self, service, valid_resource):
        valid_resource.birth_date = date(1985, 6, 15)
        valid_resource.deceased_date_time = datetime(
            1980, 1, 1, tzinfo=timezone.utc
        )
        with pytest.raises(ValidationError) as exc:
            service.create_patient(valid_resource)
        _assert_validation_error(exc, field_hint="deceased_date_time")

    def test_deceased_equals_birth_date_is_valid(self, service, valid_resource):
        """Edge: a patient born and died on the same day (e.g., neonatal death)."""
        valid_resource.birth_date = date(1985, 6, 15)
        valid_resource.deceased_date_time = datetime(
            1985, 6, 15, tzinfo=timezone.utc
        )
        result = service.create_patient(valid_resource)
        assert result.id is not None

    def test_deceased_one_second_in_future_is_rejected(self, service, valid_resource):
        valid_resource.deceased_date_time = datetime.now(timezone.utc) + timedelta(
            seconds=1
        )
        with pytest.raises(ValidationError) as exc:
            service.create_patient(valid_resource)
        _assert_validation_error(exc, field_hint="deceased_date_time")


